try {
  const rawTitle = document.title || '';
  const title = rawTitle.replace(/\s*[-\u2013]\s*Gemini\s*$/i, '').trim() || 'Gemini Chat';

  let pairs = [];

  // Strategy 1: <user-query> and <model-response> custom elements (Gemini 2024+)
  const userQueryEls = document.querySelectorAll('user-query');
  const modelRespEls = document.querySelectorAll('model-response');
  if (userQueryEls.length > 0 || modelRespEls.length > 0) {
    const max = Math.max(userQueryEls.length, modelRespEls.length);
    for (let i = 0; i < max; i++) {
      if (userQueryEls[i]) pairs.push({ role: 'User',   text: userQueryEls[i].innerText.trim() });
      if (modelRespEls[i]) pairs.push({ role: 'Gemini', text: modelRespEls[i].innerText.trim() });
    }
  }

  // Strategy 2: data-message-author-role attribute
  if (pairs.length === 0) {
    const msgEls = document.querySelectorAll('[data-message-author-role]');
    for (const el of msgEls) {
      const role = el.getAttribute('data-message-author-role') === 'user' ? 'User' : 'Gemini';
      pairs.push({ role, text: el.innerText.trim() });
    }
  }

  // Strategy 3: class-based fallback
  if (pairs.length === 0) {
    const userEls  = document.querySelectorAll('.query-text, .user-query-text');
    const modelEls = document.querySelectorAll('.model-response-text, .response-content');
    const max = Math.max(userEls.length, modelEls.length);
    for (let i = 0; i < max; i++) {
      if (userEls[i])  pairs.push({ role: 'User',   text: userEls[i].innerText.trim() });
      if (modelEls[i]) pairs.push({ role: 'Gemini', text: modelEls[i].innerText.trim() });
    }
  }

  const validPairs = pairs.filter(p => p.text);
  const lines = validPairs.map(p => `**${p.role}:**\n\n${p.text}`);

  const content = lines.length > 0
    ? lines.join('\n\n---\n\n')
    : '<!-- No conversation messages found. Open a Gemini conversation first (URL: gemini.google.com/app/XXXXXX). -->';

  console.log('[Gemini Download] title:', title, '| messages:', validPairs.length);
  automaSetVariable('title',    title);
  automaSetVariable('content',  content);
  automaSetVariable('msgCount', String(validPairs.length));
  automaNextBlock({ data: 'scraped ' + validPairs.length + ' messages from: ' + title });
} catch (err) {
  console.error('[Gemini Download] Scrape error:', err.message);
  automaSetVariable('title',    'gemini-error');
  automaSetVariable('content',  'Error during scrape: ' + err.message);
  automaSetVariable('msgCount', '0');
  automaNextBlock({ data: 'scrape error: ' + err.message });
}

try {
  const title   = automaRefData('variables', 'title')   || 'gemini';
  const content = automaRefData('variables', 'content') || '';

  const today    = new Date().toISOString().slice(0, 10);
  const markdown = `# ${title}\n\n> Downloaded: ${today}  \n> Source: ${location.href}\n\n---\n\n${content}\n`;

  const filename = (title
    .replace(/[^a-z0-9]/gi, '_')
    .replace(/_+/g, '_')
    .replace(/^_|_$/g, '')
    .toLowerCase() || 'gemini') + '.md';

  const blob = new Blob([markdown], { type: 'text/markdown' });
  const url  = URL.createObjectURL(blob);
  const a    = document.createElement('a');
  a.href     = url;
  a.download = filename;
  document.body.appendChild(a);
  a.click();
  setTimeout(() => { URL.revokeObjectURL(url); a.remove(); }, 1000);

  console.log('[Gemini Download] File saved as:', filename);
  automaSetVariable('filename', filename);
  automaNextBlock({ data: 'saved: ' + filename });
} catch (err) {
  console.error('[Gemini Download] Download error:', err.message);
  automaNextBlock({ data: 'download error: ' + err.message });
}
